/// 学習時と同じ正規化 + Linear(26→16) → ReLU → Linear(16→1) の forward pass。
/// 出力は粒子の対数重み（呼び出し側で clamp(-15, 15)）
pub fn particle_nn_forward(features: &[f64; 26]) -> f64 {
    let mut x = [0.0f64; 26];
    for i in 0..26 {
        x[i] = (features[i] - PARTICLE_NN_MEAN[i]) / PARTICLE_NN_STD[i];
    }
    let mut h = [0.0f64; 16];
    for j in 0..16 {
        let mut s = PARTICLE_NN_B1[j];
        for i in 0..26 {
            s += PARTICLE_NN_W1[j][i] * x[i];
        }
        h[j] = s.max(0.0); // ReLU
    }
    let mut out = PARTICLE_NN_B2;
    for j in 0..16 {
        out += PARTICLE_NN_W2[j] * h[j];
    }
    out
}

#[cfg(test)]
mod tests {
    use super::*;

    /// プレースホルダ（ゼロ重み = 全粒子一様）のまま誤ってマージ・凍結する
    /// 事故のガード（opp_move_nn と同じ）
    #[test]
    fn weights_are_not_placeholder_zeros() {
        assert!(
            PARTICLE_NN_W1.iter().flatten().any(|&w| w != 0.0),
            "W1が全ゼロ = export_particle_weights.py 未実行のプレースホルダ"
        );
        assert!(PARTICLE_NN_W2.iter().any(|&w| w != 0.0));
    }

    /// numpy側で同じ定数（このファイルのAUTO-GENERATED区間）を独立に読み直して
    /// 計算した値との突き合わせ（行列の転置・インデックス取り違えの検出用）。
    /// 期待値の再生成: tsuitate-nn/scripts/crosscheck_particle.py
    #[test]
    fn matches_numpy_cross_check() {
        let zeros = [0.0f64; 26];
        let mut initial_like = [0.0f64; 26];
        initial_like[4] = 1.0; // pieces_home
        for f in &mut initial_like[8..13] {
            *f = 1.0; // pawns..golds home
        }
        initial_like[13] = 1.0; // bishop_home
        initial_like[14] = 1.0; // rook_home
        initial_like[21] = 0.6; // defended_frac
        initial_like[23] = 0.02; // ply
        let mut developed = [0.0f64; 26];
        developed[0] = 1.0; // king_moved
        developed[1] = 2.0; // king_advance
        developed[3] = 1.5; // pawn_advance
        developed[4] = 0.5; // pieces_home
        developed[8] = 0.5;
        developed[15] = 3.0; // pawn_advance_max
        developed[16] = 2.0; // nonpawn_advance_max
        developed[17] = 0.4; // promoted_count
        developed[18] = 0.4; // opp_hand_count
        developed[19] = 0.4; // attacked_by_me
        developed[22] = 0.2; // king_zone_attackers
        developed[23] = 0.8; // ply
        developed[24] = 0.4; // my_dead
        developed[25] = 1.0; // you_in_check
        let cases: [([f64; 26], f64); 3] = [
            (zeros, 14.392372641864084),
            (initial_like, -3.835526678035925),
            (developed, 6.722013641020555),
        ];
        for (features, expected) in cases {
            let got = particle_nn_forward(&features);
            assert!(
                (got - expected).abs() < 1e-9,
                "features={features:?} got={got} expected={expected}"
            );
        }
    }

    /// stratified_sample はユニーク粒子ごとに1回呼ぶ（1手あたり数百回）。
    /// 特徴量抽出のほうが支配的だが、forward 自体の劣化も検出しておく
    #[test]
    fn forward_pass_is_fast_enough() {
        let mut features = [0.0f64; 26];
        features[0] = 1.0;
        features[4] = 0.8;
        let n = 100_000;
        let start = std::time::Instant::now();
        let mut acc = 0.0f64;
        for _ in 0..n {
            acc += particle_nn_forward(&std::hint::black_box(features));
        }
        let elapsed = start.elapsed();
        std::hint::black_box(acc);
        let threshold = if cfg!(debug_assertions) { 1e-4 } else { 1e-5 };
        assert!(
            elapsed.as_secs_f64() / f64::from(n) < threshold,
            "forward passが遅すぎる: {elapsed:?} / {n}回"
        );
    }
}
